state.current = item;
Object.keys(item).forEach(key => { if (form.elements[key]) form.elements[key].value = item[key] ?? ''; });
if (form.elements.type_id) form.elements.type_id.value = item.type_id || '';
updatePhoto(item.cover_photo_url);
updateGps(item);
